import{_ as t,c as a,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"專案初始化: 建立 Agent 長期記憶 | opencode-supermemory","description":"學習如何使用 /supermemory-init 指令讓 Agent 深度掃描程式碼庫，自動提取架構和規範並存入持久記憶，實現跨會話的上下文保持。","frontmatter":{"title":"專案初始化: 建立 Agent 長期記憶 | opencode-supermemory","sidebarTitle":"專案初始化","subtitle":"專案初始化：建立第一印象","description":"學習如何使用 /supermemory-init 指令讓 Agent 深度掃描程式碼庫，自動提取架構和規範並存入持久記憶，實現跨會話的上下文保持。","tags":["初始化","記憶生成","工作流程"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"zh-tw/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"zh-tw/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),i={name:"zh-tw/supermemoryai/opencode-supermemory/start/initialization/index.md"};function r(n,e,l,d,c,p){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="專案初始化-建立第一印象" tabindex="-1">專案初始化：建立第一印象 <a class="header-anchor" href="#專案初始化-建立第一印象" aria-label="Permalink to &quot;專案初始化：建立第一印象&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li><strong>一鍵熟悉專案</strong>：讓 Agent 像新入職員工一樣，主動探索並理解整個程式碼庫。</li><li><strong>建立長期記憶</strong>：自動提取專案的技術堆疊、架構模式和編碼規範，存入 Supermemory。</li><li><strong>消除重複解釋</strong>：再也不用在每次會話開始時重複「我們用的是 Bun」或「所有元件都要寫測試」。</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你是否遇到過這些情況：</p><ul><li><strong>重複勞動</strong>：每次開啟新會話，都要花大量篇幅告訴 Agent 專案的基本情況。</li><li><strong>上下文遺忘</strong>：Agent 經常忘記專案特定的目錄結構，把檔案建錯位置。</li><li><strong>規範不統一</strong>：Agent 寫的程式碼風格飄忽不定，一會兒用 <code>interface</code> 一會兒用 <code>type</code>。</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li><strong>剛安裝外掛後</strong>：這是使用 opencode-supermemory 的第一步。</li><li><strong>接手新專案時</strong>：快速建立該專案的記憶庫。</li><li><strong>重大重構後</strong>：當專案架構發生變化，需要更新 Agent 的認知時。</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置檢查</p><p>請確保你已經完成了 <a href="./../getting-started/">快速開始</a> 中的安裝和配置步驟，並且 <code>SUPERMEMORY_API_KEY</code> 已正確設定。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><code>/supermemory-init</code> 指令本質上不是一個二進制程序，而是一個<strong>精心設計的 Prompt</strong>（提示詞）。</p><p>當你執行這個指令時，它會向 Agent 發送一份詳細的「入職指南」，指示 Agent：</p><ol><li><strong>深度調研</strong>：主動閱讀 <code>README.md</code>、<code>package.json</code>、Git 提交記錄等。</li><li><strong>結構化分析</strong>：識別專案的技術堆疊、架構模式、隱式約定。</li><li><strong>持久化儲存</strong>：使用 <code>supermemory</code> 工具將這些洞察存入雲端資料庫。</li></ol><div class="info custom-block"><p class="custom-block-title">記憶作用域</p><p>初始化過程會區分兩種記憶：</p><ul><li><strong>Project Scope</strong>：僅對當前專案生效（如：建置指令、目錄結構）。</li><li><strong>User Scope</strong>：對你所有專案生效（如：你偏好的程式碼風格）。</li></ul></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-執行初始化指令" tabindex="-1">第 1 步：執行初始化指令 <a class="header-anchor" href="#第-1-步-執行初始化指令" aria-label="Permalink to &quot;第 1 步：執行初始化指令&quot;">​</a></h3><p>在 OpenCode 的輸入框中，輸入以下指令並發送：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>為什麼</strong> 這會載入預定義的 Prompt，啟動 Agent 的探索模式。</p><p><strong>你應該看到</strong> Agent 開始回覆，表示它理解了任務，並開始規劃調研步驟。它可能會說：&quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="第-2-步-觀察-agent-的探索過程" tabindex="-1">第 2 步：觀察 Agent 的探索過程 <a class="header-anchor" href="#第-2-步-觀察-agent-的探索過程" aria-label="Permalink to &quot;第 2 步：觀察 Agent 的探索過程&quot;">​</a></h3><p>Agent 會自動執行一系列操作，你只需要看著就行。它通常會：</p><ol><li><strong>讀取配置檔案</strong>：讀取 <code>package.json</code>、<code>tsconfig.json</code> 等了解技術堆疊。</li><li><strong>查看 Git 歷史</strong>：執行 <code>git log</code> 了解提交規範和活躍貢獻者。</li><li><strong>探索目錄結構</strong>：使用 <code>ls</code> 或 <code>list_files</code> 查看專案佈局。</li></ol><p><strong>範例輸出</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">消耗提示</p><p>這個過程是一次深度調研，可能會消耗較多的 Token（通常會進行 50+ 次工具呼叫）。請耐心等待，直到 Agent 報告完成。</p></div><h3 id="第-3-步-驗證生成的記憶" tabindex="-1">第 3 步：驗證生成的記憶 <a class="header-anchor" href="#第-3-步-驗證生成的記憶" aria-label="Permalink to &quot;第 3 步：驗證生成的記憶&quot;">​</a></h3><p>當 Agent 提示初始化完成後，你可以檢查一下它到底記住了什麼。輸入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 列出當前專案的記憶</span></span></code></pre></div><p>或者直接呼叫工具（如果你想看原始資料）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>你應該看到</strong> Agent 列出了一系列結構化的記憶，例如：</p><table tabindex="0"><thead><tr><th>類型</th><th>內容範例</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="第-4-步-補充遺漏-可選" tabindex="-1">第 4 步：補充遺漏（可選） <a class="header-anchor" href="#第-4-步-補充遺漏-可選" aria-label="Permalink to &quot;第 4 步：補充遺漏（可選）&quot;">​</a></h3><p>如果 Agent 漏掉了某些關鍵資訊（比如某個只有口頭約定的特殊規則），你可以手動補充：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>請記住：在這個專案中，所有的日期處理必須使用 dayjs 函式庫，禁止使用原生 Date。</span></span></code></pre></div><p><strong>你應該看到</strong> Agent 回覆確認，並呼叫 <code>supermemory(mode: &quot;add&quot;)</code> 儲存這條新規則。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] 執行 <code>/supermemory-init</code> 後，Agent 是否自動執行了探索任務？</li><li>[ ] 使用 <code>list</code> 指令是否能查看到新生成的記憶？</li><li>[ ] 記憶內容是否準確反映了當前專案的實際情況？</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">不要頻繁執行</p><p>初始化是一個耗時且消耗 Token 的過程。通常每個專案只需要執行一次。只有在專案發生巨大變化時才需要重新執行。</p></div><div class="danger custom-block"><p class="custom-block-title">隱私注意</p><p>雖然外掛會自動脫敏 <code>&lt;private&gt;</code> 標籤的內容，但在初始化過程中，Agent 會讀取大量檔案。請確保你的程式碼庫中沒有硬編碼的敏感金鑰（如 AWS Secret Key），否則它們可能會被作為「專案配置」存入記憶。</p></div><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>透過 <code>/supermemory-init</code>，我們完成了從「陌生人」到「熟練工」的轉變。現在，Agent 已經記住了專案的核心架構和規範，在接下來的編碼任務中，它將自動利用這些上下文，為你提供更精準的輔助。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../../core/context-injection/">自動上下文注入機制</a></strong>。</p><p>你會學到：</p><ul><li>Agent 是如何在會話開始時「想起」這些記憶的。</li><li>如何透過關鍵詞觸發特定的記憶召回。</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>初始化 Prompt 定義</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>記憶工具實作</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>：定義了 <code>/supermemory-init</code> 指令的具體 Prompt 內容，指導 Agent 如何進行調研和記憶。</li></ul></details>`,50)])])}const g=t(i,[["render",r]]);export{u as __pageData,g as default};
